114:   for (let i = days - 1; i >= 0; i--) {
115:     const d = new Date(today);
116:     d.setDate(today.getDate() - i);
117:     const x = days - 1 - i;
118:     let ndvi: number;
119:     if (x < 60) {
120:       ndvi = 0.3 + (x / 60) * 0.5 + Math.sin(x / 5) * 0.02;
121:     } else if (x < 80) {
122:       ndvi = 0.78 + Math.sin(x / 4) * 0.015;
123:     } else {
124:       const dropPct = (x - 80) / 10;
125:       ndvi = 0.78 - dropPct * 0.36 + Math.sin(x / 3) * 0.01;
126:     }
